def seed_strains():
    print(f"Seeding {len(STRAINS)} strains...")
    for strain in STRAINS:
        try:
            supabase.table("strains").upsert(strain, on_conflict="slug").execute()
            print(f"  + {strain['name']}")
        except Exception as e:
            print(f"  ! {strain['name']}: {e}")


def seed_products():
    print(f"Seeding {len(PRODUCTS)} products...")
    for product in PRODUCTS:
        try:
            supabase.table("products").upsert(product, on_conflict="sku").execute()
            print(f"  + {product['name']}")
        except Exception as e:
            print(f"  ! {product['name']}: {e}")


if __name__ == "__main__":
    print("Frost Seed Script")
    print("=" * 50)
    seed_strains()
    print()
    seed_products()
    print()
    print("Done!")
